import { UnionFind } from './UnionFind';

function solve(c, connections, queries) {
    // Initialize Union-Find structure for the grid
    const uf = new UnionFind(c);

    // Process the connections to build the grid
    for (const [u, v] of connections) {
        uf.union(u, v);
    }

    const result = [];

    // Keep track of which nodes are online
    const online = new Array(c + 1).fill(true);

    // Process each query
    for (const [type, x] of queries) {
        if (type === 1) {
            // Maintenance check query
            if (online[x]) {
                result.push(x);
            } else {
                // Find the root of the grid that x is in
                const root = uf.find(x);
                // Find the minimum online node in the same grid
                let minOnline = -1;
                for (let i = 1; i <= c; i++) {
                    if (uf.find(i) === root && online[i]) {
                        if (minOnline === -1 || i < minOnline) {
                            minOnline = i;
                        }
                    }
                }
                result.push(minOnline);
            }
        } else {
            // Offline query
            online[x] = false;
        }
    }

    return result;
}

class UnionFind {
    constructor(size) {
        this.parent = Array(size + 1).fill(0).map((_, i) => i);
        this.rank = Array(size + 1).fill(0);
    }

    find(x) {
        if (this.parent[x] !== x) {
            this.parent[x] = this.find(this.parent[x]);
        }
        return this.parent[x];
    }

    union(x, y) {
        const xRoot = this.find(x);
        const yRoot = this.find(y);

        if (xRoot === yRoot) return;

        if (this.rank[xRoot] < this.rank[yRoot]) {
            this.parent[xRoot] = yRoot;
        } else {
            this.parent[yRoot] = xRoot;
            if (this.rank[xRoot] === this.rank[yRoot]) {
                this.rank[xRoot]++;
            }
        }
    }
}

