import java.util.Arrays;

public class Solution {
    public static long[] solve(long c, long[][] connections, long[][] queries) {
        // Initialize Union-Find structure for the grid
        UnionFind uf = new UnionFind((int) c);

        // Process the connections to build the grid
        for (long[] conn : connections) {
            long u = conn[0];
            long v = conn[1];
            uf.union((int) u, (int) v);
        }

        // Keep track of which nodes are online
        boolean[] online = new boolean[(int) c + 1];
        Arrays.fill(online, true);

        // Process each query
        long[] result = new long[queries.length];
        int idx = 0;

        for (long[] query : queries) {
            long type = query[0];
            long x = query[1];

            if (type == 1) {
                // Maintenance check query
                if (online[(int) x]) {
                    result[idx++] = x;
                } else {
                    // Find the root of the grid that x is in
                    long root = uf.find((int) x);
                    // Find the minimum online node in the same grid
                    long minOnline = -1;
                    for (int i = 1; i <= (int) c; i++) {
                        if (uf.find(i) == root && online[i]) {
                            if (minOnline == -1 || i < minOnline) {
                                minOnline = i;
                            }
                        }
                    }
                    result[idx++] = minOnline;
                }
            } else {
                // Offline query
                online[(int) x] = false;
            }
        }

        return Arrays.copyOf(result, idx);
    }
}

class UnionFind {
    private int[] parent;
    private int[] rank;

    public UnionFind(int size) {
        parent = new int[size + 1];
        rank = new int[size + 1];
        for (int i = 0; i <= size; i++) {
            parent[i] = i;
            rank[i] = 0;
        }
    }

    public int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    public void union(int x, int y) {
        int xRoot = find(x);
        int yRoot = find(y);

        if (xRoot == yRoot) return;

