public class Solution {
    public static long[] solve(long c, long[][] connections, long[][] queries) {
        // Initialize Union-Find structure for the grid
        UnionFind uf = new UnionFind((int) c);

        // Process the connections to build the grid
        for (int i = 0; i < connections.length; i++) {
            long u = connections[i][0];
            long v = connections[i][1];
            uf.union((int) u, (int) v);
        }

        // Keep track of which nodes are online
        boolean[] online = new boolean[(int) c + 1];
        for (int i = 1; i <= (int) c; i++) {
            online[i] = true;
        }

        // Process each query
        List<Long> result = new ArrayList<>();

        for (int i = 0; i < queries.length; i++) {
            long type = queries[i][0];
            long x = queries[i][1];

            if (type == 1) {
                // Maintenance check query
                if (online[(int) x]) {
                    result.add((long) x);
                } else {
                    // Find the root of the grid that x is in
                    int root = uf.find((int) x);
                    // Find the minimum online node in the same grid
                    long minOnline = -1;
