                            }
                        }
                    }
                    result.add(minOnline);
                }
            } else {
                // Offline query
                online[(int) x] = false;
            }
        }

        // Convert the list to an array
        long[] resultArray = new long[result.size()];
        for (int i = 0; i < result.size(); i++) {
            resultArray[i] = result.get(i);
        }

        return resultArray;
    }

