        int[] parent;
        int[] rank;

        UnionFind(int size) {
            parent = new int[size + 1];
            rank = new int[size + 1];
            for (int i = 0; i <= size; i++) {
                parent[i] = i;
                rank[i] = 0;
            }
        }

